      const a = points[i];
      const b = points[(i + 1) % points.length];
      const dx = b.x - a.x;
      const dz = b.z - a.z;
      const length = Math.sqrt(dx * dx + dz * dz);
      const wall = new THREE.Mesh(new THREE.BoxGeometry(length, this.height, 0.1), material);
      wall.position.set((a.x + b.x) / 2, this.height / 2, (a.z + b.z) / 2);
      wall.rotation.y = -Math.atan2(dz, dx); // Corrected rotation
      wall.castShadow = true;
      wall.receiveShadow = true;
      this.group.add(wall);
    }
  }
