// src/three/objects/Room.js
// Class for creating a room from custom polygon points

import * as THREE from 'three';

export class Room {
  constructor(height = 3) {
    this.height = height;
    this.group = new THREE.Group();
    this.group.userData.selectable = false; // Room group
  }

  buildFromPolygon(points) {
    this.clearRoom(); // remove old geometry
    this.createFloor(points);
    this.createWalls(points);
    this.createCeiling(points);
    this.centerGroup(points);  // ✅ center room around origin
  }



  // Clear existing meshes
  clear() {
    while (this.group.children.length > 0) {
      this.group.remove(this.group.children[0]);
    }
  }

  clearRoom() {
    // Remove all children from the group (floor, walls, ceiling)
    while (this.group.children.length > 0) {
      this.group.remove(this.group.children[0]);
    }
  }


  createFloor(points) {
    const shape = new THREE.Shape(points.map(p => new THREE.Vector2(p.x, p.z)));
    const geometry = new THREE.ShapeGeometry(shape);
    geometry.rotateX(-Math.PI / 2);

    const texture = new THREE.TextureLoader().load('/assets/textures/room/hardwood.png');
    texture.wrapS = texture.wrapT = THREE.RepeatWrapping;
    texture.repeat.set(4, 4);

    const material = new THREE.MeshStandardMaterial({
      map: texture,
      color: 0xcccccc,
      roughness: 0.8,
      metalness: 0.2,
      side: THREE.DoubleSide
    });

    const floor = new THREE.Mesh(geometry, material);
    floor.receiveShadow = true;
    floor.userData.isFloor = true;
    this.group.add(floor);

    // ✅ Debug log
    console.log("✅ Floor created with points:", points);
  }

  createWalls(points) {
    const material = new THREE.MeshStandardMaterial({
      color: 0xffffff,
      roughness: 0.7,
      metalness: 0.0,
      side: THREE.FrontSide
    });

    for (let i = 0; i < points.length; i++) {
      const a = points[i];
      const b = points[(i + 1) % points.length];

      const dx = b.x - a.x;
      const dz = b.z - a.z;
      const length = Math.sqrt(dx * dx + dz * dz);

      const wall = new THREE.Mesh(
        new THREE.BoxGeometry(length, this.height, 0.1),
        material
      );

      wall.position.set((a.x + b.x) / 2, this.height / 2, (a.z + b.z) / 2);
      wall.rotation.y = -Math.atan2(dz, dx);  // Corrected rotation
      wall.castShadow = true;
      wall.receiveShadow = true;

      this.group.add(wall);
    }
  }

  centerGroup(points) {
    const center = points.reduce((acc, p) => {
      acc.x += p.x;
      acc.z += p.z;
      return acc;
    }, { x: 0, z: 0 });

    center.x /= points.length;
    center.z /= points.length;

    this.group.position.set(-center.x, 0, -center.z);
  }



  createCeiling(points) {
    const shape = new THREE.Shape(points.map(p => new THREE.Vector2(p.x, p.z)));
    const geometry = new THREE.ShapeGeometry(shape);
    geometry.rotateX(Math.PI / 2); // Face down

    const material = new THREE.MeshStandardMaterial({
      color: 0xeeeeee,
      roughness: 0.8,
      metalness: 0.0,
      side: THREE.DoubleSide
    });

    const ceiling = new THREE.Mesh(geometry, material);
    ceiling.position.y = this.height;
    ceiling.receiveShadow = true;
    ceiling.userData.isCeiling = true;
    this.group.add(ceiling);

    // ✅ Debug log
    console.log("✅ Ceiling created at height:", this.height);
  }


  // Change wall color dynamically
  setWallColor(color) {
    this.group.traverse(obj => {
      if (obj.userData.isWall && obj.material) {
        obj.material.color.set(color);
      }
    });
  }

  // Change floor texture dynamically
  setFloorTexture(texturePath) {
    this.group.traverse(obj => {
      if (obj.userData.isFloor && obj.material.map) {
        const texture = new THREE.TextureLoader().load(texturePath);
        texture.wrapS = texture.wrapT = THREE.RepeatWrapping;
        texture.repeat.set(4, 4);
        obj.material.map = texture;
        obj.material.needsUpdate = true;
      }
    });
  }

  toggleCeiling() {
    this.group.traverse(obj => {
      if (obj.userData.isCeiling) {
        obj.visible = !obj.visible;
      }
    });
  }
}
